import { NextResponse } from 'next/server'
import { hash } from 'bcryptjs'
import { sql } from '@/lib/db'
import fs from 'fs'
import path from 'path'

export async function GET() {
    try {
        console.log('--- Starting Database Initialization ---')

        // 1. Read the schema file
        const schemaPath = path.join(process.cwd(), 'scripts', '001-create-tables.sql')
        const schemaSql = fs.readFileSync(schemaPath, 'utf8')

        // Optional: Drop existing tables for a clean start if needed
        // We'll do it to ensure the 'slug' and 'full_name' changes are applied
        const dropTablesSql = `
      DROP TABLE IF EXISTS stock_movements CASCADE;
      DROP TABLE IF EXISTS alerts CASCADE;
      DROP TABLE IF EXISTS vehicle_inventory CASCADE;
      DROP TABLE IF EXISTS tour_stops CASCADE;
      DROP TABLE IF EXISTS delivery_tours CASCADE;
      DROP TABLE IF EXISTS vehicles CASCADE;
      DROP TABLE IF EXISTS payments CASCADE;
      DROP TABLE IF EXISTS packaging_transactions CASCADE;
      DROP TABLE IF EXISTS sales_order_items CASCADE;
      DROP TABLE IF EXISTS sales_orders CASCADE;
      DROP TABLE IF EXISTS client_accounts CASCADE;
      DROP TABLE IF EXISTS clients CASCADE;
      DROP TABLE IF EXISTS purchase_order_items CASCADE;
      DROP TABLE IF EXISTS purchase_orders CASCADE;
      DROP TABLE IF EXISTS suppliers CASCADE;
      DROP TABLE IF EXISTS packaging_stock CASCADE;
      DROP TABLE IF EXISTS stock CASCADE;
      DROP TABLE IF EXISTS depots CASCADE;
      DROP TABLE IF EXISTS packaging_equivalences CASCADE;
      DROP TABLE IF EXISTS product_variants CASCADE;
      DROP TABLE IF EXISTS packaging_types CASCADE;
      DROP TABLE IF EXISTS products CASCADE;
      DROP TABLE IF EXISTS role_permissions CASCADE;
      DROP TABLE IF EXISTS users CASCADE;
      DROP TABLE IF EXISTS companies CASCADE;
      DROP TABLE IF EXISTS subscription_plans CASCADE;
    `
        for (const statement of dropTablesSql.split(';').map(s => s.trim()).filter(s => s.length > 0)) {
            await sql(statement as any)
        }

        // 2. Execute the schema
        // Remove comments and split by semicolon
        const sqlContent = schemaSql
            .replace(/--.*$/gm, '') // Remove single line comments
            .replace(/\/\*[\s\S]*?\*\//g, '') // Remove multi-line comments

        const statements = sqlContent
            .split(';')
            .map(s => s.trim())
            .filter(s => s.length > 0)

        for (const statement of statements) {
            try {
                await sql(statement as any)
            } catch (err: any) {
                // Ignore errors for "IF NOT EXISTS" type failures if they happen
                console.warn(`Warning executing statement: ${statement.slice(0, 50)}...`, err.message)
            }
        }

        console.log('✅ Tables created successfully.')

        // 3. Seed Admin
        const email = 'admin@bstock.com'
        const password = 'adminpassword123'
        const companyName = 'B-Stock Demo Corp'
        const fullName = 'Administrateur Démo'

        const existing = await sql`SELECT id FROM users WHERE email = ${email}`
        if (existing.length === 0) {
            const passwordHash = await hash(password, 12)
            const slug = 'demo-corp-' + Math.random().toString(36).substring(7)
            const trialEndsAt = new Date()
            trialEndsAt.setDate(trialEndsAt.getDate() + 365)

            const companies = await sql`
        INSERT INTO companies (name, slug, email, subscription_status, trial_ends_at)
        VALUES (${companyName}, ${slug}, ${email}, 'active', ${trialEndsAt.toISOString()})
        RETURNING id
      `
            const companyId = companies[0].id

            await sql`
        INSERT INTO users (company_id, email, password_hash, full_name, role)
        VALUES (${companyId}, ${email}, ${passwordHash}, ${fullName}, 'owner')
      `

            await sql`
        INSERT INTO depots (company_id, name, is_main)
        VALUES (${companyId}, 'Entrepôt Central', true)
      `
            console.log('✅ Admin seeded.')
        } else {
            console.log('ℹ️ Admin already exists.')
        }

        return NextResponse.json({
            success: true,
            message: 'Database initialized and admin seeded.',
            credentials: { email: 'admin@bstock.com', password: 'adminpassword123' }
        })
    } catch (error: any) {
        console.error('Initialization error:', error)
        return NextResponse.json({ success: false, error: error.message }, { status: 500 })
    }
}
